		if err != nil {
			http.Error(w, "Invalid JWT signature", http.StatusUnauthorized)
			return
		}

		claims := token.Claims.(jwt.MapClaims)
		userID := claims["user_id"].(float64) // Assuming user_id is present in the JWT claim and it's a float64

		// Create a new context with the extracted user information
		ctx := context.WithValue(r.Context(), "user", CustomClaims{UserID: int64(userID)})
		r = r.WithContext(ctx)

		next.ServeHTTP(w, r)
